// NEW COMMANDS: Export, Expand, Timeline
// ============================================================================

/// Detect if a path points to an OpenCode storage session file.
/// OpenCode stores sessions in: storage/session/{projectID}/{sessionID}.json
fn detect_opencode_session(path: &Path) -> bool {
    // Must be a JSON file
    if path.extension().map(|e| e != "json").unwrap_or(true) {
        return false;
    }

    // Primary check: verify directory structure
    // Path should be: {storage_root}/session/{projectID}/{sessionID}.json
    // with sibling message/ and/or part/ directories
    if let Some(parent) = path.parent()
        && let Some(session_dir) = parent.parent()
        && session_dir
            .file_name()
            .map(|n| n == "session")
            .unwrap_or(false)
        && let Some(storage_root) = session_dir.parent()
    {
        let message_dir = storage_root.join("message");
        let part_dir = storage_root.join("part");
        if message_dir.exists() || part_dir.exists() {
            return true;
        }
    }

    // Fallback: check if path follows opencode naming convention
    // Pattern: .../opencode/storage/session/...
    let components: Vec<_> = path.components().map(|c| c.as_os_str()).collect();
    for window in components.windows(3) {
        let w0 = window[0].to_string_lossy().to_lowercase();
        let w1 = window[1].to_string_lossy().to_lowercase();
        let w2 = window[2].to_string_lossy().to_lowercase();
        if w0.contains("opencode") && w1 == "storage" && w2 == "session" {
            return true;
        }
    }

    false
}

/// Detect if a path points to an OpenCode SQLite-backed session.
///
/// These paths look like `<prefix>/opencode.db/<url-encoded-session-id>` and are
/// produced by the OpenCode connector when indexing from the SQLite database.
/// The actual file at that path does not exist -- the session lives inside
/// the `.db` file.
fn detect_opencode_sqlite_session(path: &Path) -> bool {
    // Walk ancestors looking for a component that ends in ".db"
    if let Some(parent) = path.parent() {
        let parent_name = parent
            .file_name()
            .map(|n| n.to_string_lossy())
            .unwrap_or_default();
        if parent_name.ends_with(".db") && parent.is_file() {
            // The parent is a real .db file and the child is the session id
            return true;
        }
    }
    false
}

fn path_exists_or_virtual_opencode_sqlite_session(path: &Path, allow_direct_file: bool) -> bool {
    path.exists() || (allow_direct_file && detect_opencode_sqlite_session(path))
}

/// Load an OpenCode session from the SQLite database for export.
///
/// `path` is expected to be `<dir>/opencode.db/<url-encoded-session-id>`.
/// Returns (title, start_ts, end_ts, messages as JSON values).
#[allow(clippy::type_complexity)]
fn load_opencode_sqlite_session_for_export(
    path: &Path,
) -> anyhow::Result<(
    Option<String>,
    Option<i64>,
    Option<i64>,
    Vec<serde_json::Value>,
)> {
    use anyhow::Context;

    let session_id_encoded = path
        .file_name()
        .context("missing session id in path")?
        .to_string_lossy();
    let session_id =
        urlencoding::decode(&session_id_encoded).unwrap_or_else(|_| session_id_encoded.clone());
    let db_path = path.parent().context("missing parent db path")?;

    use franken_agent_detection::connectors::Connector;
    let connector = franken_agent_detection::OpenCodeConnector::new();
    let scan_ctx = franken_agent_detection::connectors::ScanContext::local_default(
        db_path.to_path_buf(),
        None,
    );
    let convs = connector.scan(&scan_ctx)?;

    // Find the conversation matching the session id
    let conv = convs
        .into_iter()
        .find(|c| c.external_id.as_deref() == Some(session_id.as_ref()))
        .with_context(|| {
            format!(
                "session '{}' not found in OpenCode database at {}",
                session_id,
                db_path.display()
            )
        })?;

    let mut messages: Vec<serde_json::Value> = Vec::new();
    for msg in &conv.messages {
        let mut msg_json = serde_json::json!({
            "role": msg.role,
            "content": msg.content,
        });
        if let Some(ts) = msg.created_at {
            msg_json["timestamp"] = serde_json::Value::from(ts);
        }
        if let Some(author) = &msg.author {
            msg_json["model"] = serde_json::Value::from(author.clone());
        }
        messages.push(msg_json);
    }

    Ok((conv.title, conv.started_at, conv.ended_at, messages))
}

/// Load an OpenCode session for export.
/// Returns (title, start_ts, end_ts, messages as JSON values).
#[allow(clippy::type_complexity)]
fn load_opencode_session_for_export(
    session_path: &Path,
) -> anyhow::Result<(
    Option<String>,
    Option<i64>,
    Option<i64>,
    Vec<serde_json::Value>,
)> {
    use anyhow::Context;
    use std::collections::HashMap;
    use walkdir::WalkDir;

    let normalize_opencode_ts = |ts: Option<i64>| {
        ts.and_then(|raw| crate::connectors::parse_timestamp(&serde_json::Value::from(raw)))
    };

    // Parse session file
    let session_content = std::fs::read_to_string(session_path)
        .with_context(|| format!("read session file {}", session_path.display()))?;
    let session: serde_json::Value = serde_json::from_str(&session_content)
        .with_context(|| format!("parse session JSON {}", session_path.display()))?;

    let session_id = session["id"]
        .as_str()
        .context("session missing 'id' field")?;
    let session_title = session["title"].as_str().map(String::from);
    let session_start = normalize_opencode_ts(session["time"]["created"].as_i64());
    let session_end = normalize_opencode_ts(session["time"]["updated"].as_i64());

    // Find storage root by going up from session file
    // Path: storage/session/{projectID}/{sessionID}.json
    let storage_root = session_path
        .parent() // {projectID}/
        .and_then(|p| p.parent()) // session/
        .and_then(|p| p.parent()) // storage/
        .context("cannot determine storage root from session path")?;

    let message_dir = storage_root.join("message").join(session_id);
    let part_dir = storage_root.join("part");

    if !message_dir.exists() {
        anyhow::bail!("message directory not found: {}", message_dir.display());
    }

    // Build map of message_id -> parts
    #[derive(serde::Deserialize, Clone)]
    struct PartInfo {
        #[serde(rename = "messageID")]
        message_id: Option<String>,
        #[serde(rename = "type")]
        part_type: Option<String>,
        text: Option<String>,
        state: Option<PartState>,
    }
    #[derive(serde::Deserialize, Clone)]
    struct PartState {
        output: Option<String>,
    }

    let mut parts_by_msg: HashMap<String, Vec<PartInfo>> = HashMap::new();
    if part_dir.exists() {
        for entry in WalkDir::new(&part_dir).into_iter().flatten() {
            if !entry.file_type().is_file() {
                continue;
            }
            let p = entry.path();
            if p.extension().map(|e| e == "json").unwrap_or(false)
                && let Ok(content) = std::fs::read_to_string(p)
                && let Ok(part) = serde_json::from_str::<PartInfo>(&content)
                && let Some(msg_id) = &part.message_id
            {
                parts_by_msg.entry(msg_id.clone()).or_default().push(part);
            }
        }
    }

    // Load messages
    #[derive(serde::Deserialize)]
    struct MsgInfo {
        id: String,
        role: Option<String>,
        #[serde(rename = "modelID")]
        model_id: Option<String>,
        time: Option<MsgTime>,
    }
    #[derive(serde::Deserialize)]
    struct MsgTime {
        created: Option<i64>,
    }

    let mut messages: Vec<(i64, serde_json::Value)> = Vec::new();
    let mut message_ts_min: Option<i64> = None;
    let mut message_ts_max: Option<i64> = None;

    for entry in WalkDir::new(&message_dir)
        .max_depth(1)
        .into_iter()
        .flatten()
    {
        if !entry.file_type().is_file() {
            continue;
        }
        let p = entry.path();
        if !p.extension().map(|e| e == "json").unwrap_or(false) {
            continue;
        }

        let content = match std::fs::read_to_string(p) {
            Ok(c) => c,
            Err(_) => continue,
        };
        let msg_info: MsgInfo = match serde_json::from_str(&content) {
            Ok(m) => m,
            Err(_) => continue,
        };

        // Assemble content from parts
        let parts = parts_by_msg.get(&msg_info.id).cloned().unwrap_or_default();
        let mut content_pieces: Vec<String> = Vec::new();
        for part in &parts {
            match part.part_type.as_deref() {
                Some("text") => {
                    if let Some(text) = &part.text
                        && !text.trim().is_empty()
                    {
                        content_pieces.push(text.clone());
                    }
                }
                Some("tool") => {
                    if let Some(state) = &part.state
                        && let Some(output) = &state.output
                        && !output.trim().is_empty()
                    {
                        content_pieces.push(format!("[Tool Output]\n{output}"));
                    }
                }
                Some("reasoning") => {
                    if let Some(text) = &part.text
                        && !text.trim().is_empty()
                    {
                        content_pieces.push(format!("[Reasoning]\n{text}"));
                    }
                }
                Some("patch") => {
                    if let Some(text) = &part.text
                        && !text.trim().is_empty()
                    {
                        content_pieces.push(format!("[Patch]\n{text}"));
                    }
                }
                _ => {}
            }
        }

        let assembled_content = content_pieces.join("\n\n");
        if assembled_content.trim().is_empty() {
            continue;
        }

        let role = msg_info.role.unwrap_or_else(|| "assistant".to_string());
        let timestamp = normalize_opencode_ts(msg_info.time.as_ref().and_then(|t| t.created));
        if let Some(ts) = timestamp {
            message_ts_min = Some(message_ts_min.map_or(ts, |current| current.min(ts)));
            message_ts_max = Some(message_ts_max.map_or(ts, |current| current.max(ts)));
        }

        // Build JSON value matching expected format for formatters
        let mut msg_json = serde_json::json!({
            "role": role,
            "content": assembled_content,
            "model": msg_info.model_id,
        });
        if let Some(ts) = timestamp {
            msg_json["timestamp"] = serde_json::Value::from(ts);
        }

        // Keep unknown timestamps at the end while preserving deterministic output.
        messages.push((timestamp.unwrap_or(i64::MAX), msg_json));
    }

    // Sort by timestamp
    messages.sort_by_key(|(ts, _)| *ts);
    let sorted_messages: Vec<serde_json::Value> = messages.into_iter().map(|(_, m)| m).collect();

    // Compute timestamps from messages if not available in session metadata.
    let start = session_start.or(message_ts_min);
    let end = session_end.or(message_ts_max);

    Ok((session_title, start, end, sorted_messages))
}

/// Return value of [`resolve_resume_target`] — the full recipe needed
/// to resume a session in its native harness.
#[derive(Debug, Clone, PartialEq, Eq)]
struct ResumeTarget {
    /// Normalized agent slug (claude, codex, opencode, pi_agent, gemini).
    agent: &'static str,
    /// Session identifier extracted from the path or file contents, or
    /// `None` when the harness resumes by path rather than by id.
    session_id: Option<String>,
    /// Fully-resolved argv for the resume command, ready to exec.
    argv: Vec<String>,
    /// Why the agent was detected — useful for diagnostics and JSON output.
    detection_reason: String,
}

/// POSIX shell escaping for a single argument: wraps in single quotes
/// and escapes any embedded single quotes. Keeps the output suitable
/// for `eval "$(cass resume ...)"` without introducing shell injection.
fn shell_quote(arg: &str) -> String {
    if !arg.is_empty()
        && arg.chars().all(|c| {
            c.is_ascii_alphanumeric() || matches!(c, '_' | '-' | '.' | '/' | ':' | '@' | '+' | ',')
        })
    {
        // Safe characters — no quoting needed.
        return arg.to_string();
    }
    let mut out = String::with_capacity(arg.len() + 2);
    out.push('\'');
    for ch in arg.chars() {
        if ch == '\'' {
            // Close quote, emit escaped quote, reopen.
            out.push_str("'\\''");
        } else {
            out.push(ch);
        }
    }
    out.push('\'');
    out
}

/// Result of agent detection: the normalized slug, an optional
/// harness-binary hint (currently only meaningful for pi_agent, where
/// the same slug can correspond to either `pi` or `omp`), and a short
/// human-readable reason for diagnostics.
#[derive(Debug, Clone, PartialEq, Eq)]
struct DetectedAgent {
    slug: &'static str,
    /// Only set when the caller passed an unambiguous alias — e.g.
    /// `--agent omp` pins the binary to `omp`, while `--agent pi_agent`
    /// leaves it to the path-based inference inside [`resolve_resume_target`].
    binary_hint: Option<&'static str>,
    /// True when the agent was selected via an explicit `--agent`
    /// override. Used by downstream validators (e.g. the UUID-shape
    /// check for Claude Code / Codex) to decide whether to enforce
    /// strict format rules (auto-detection) or trust the user (override).
    is_override: bool,
    reason: String,
}

/// Detect which coding-agent harness owns a given session path.
///
/// Detection is path-based and mirrors the layouts that the bundled
/// connectors understand. If `agent_override` is set, its value is
/// validated and returned verbatim. Returns a normalized slug plus an
/// optional binary hint (see [`DetectedAgent::binary_hint`]).
fn detect_resume_agent(path: &Path, agent_override: Option<&str>) -> CliResult<DetectedAgent> {
    if let Some(raw) = agent_override {
        let normalized = raw.trim().to_ascii_lowercase();
        let (slug, binary_hint): (&'static str, Option<&'static str>) = match normalized.as_str() {
            "claude" | "claude_code" | "claude-code" => ("claude", None),
            "codex" => ("codex", None),
            "opencode" => ("opencode", None),
            // Generic "pi_agent" / "pi-agent": let path inference pick the binary.
            "pi_agent" | "pi-agent" => ("pi_agent", None),
            // pi-mono: user explicitly selected the `pi` binary.
            "pi" => ("pi_agent", Some("pi")),
            // Oh My Pi: user explicitly selected the `omp` binary.
            "omp" | "oh-my-pi" | "ohmypi" | "oh_my_pi" => ("pi_agent", Some("omp")),
            "gemini" => ("gemini", None),
            other => {
                return Err(CliError {
                    code: 2,
                    kind: CliErrorKind::InvalidAgent.kind_str(),
                    message: format!(
                        "unknown --agent value '{other}'; expected one of: claude, codex, opencode, pi_agent, pi, omp, gemini"
                    ),
                    hint: None,
                    retryable: false,
                });
            }
        };
        return Ok(DetectedAgent {
            slug,
            binary_hint,
            is_override: true,
            reason: format!("--agent override: {raw}"),
        });
    }

    let path_str = path.to_string_lossy();
    // Path-substring detection. These match the real on-disk layouts
    // and are ordered longest-match-first where it matters.
    //
    // We deliberately only match Claude Code via `.claude/projects`
    // (the canonical path segment). An earlier draft also matched
    // `claude_code` anywhere in the path, but that produced false
    // positives on user directories named things like
    // `~/projects/my_claude_code_extension/`. Users on unusual installs
    // can always force detection with `--agent claude`.
    if path_str.contains(".claude/projects") {
        return Ok(DetectedAgent {
            slug: "claude",
            binary_hint: None,
            is_override: false,
            reason: "path contains .claude/projects".to_string(),
        });
    }
    if path_str.contains(".codex/sessions") || path_str.contains("/codex/sessions") {
        return Ok(DetectedAgent {
            slug: "codex",
            binary_hint: None,
            is_override: false,
            reason: "path contains .codex/sessions".to_string(),
        });
    }
    if path_str.contains("opencode.db")
        || path_str.contains(".local/share/opencode")
        || path_str.contains(".config/opencode")
    {
        return Ok(DetectedAgent {
            slug: "opencode",
            binary_hint: None,
            is_override: false,
            reason: "path references opencode storage".to_string(),
        });
    }
    if path_str.contains(".omp/agent") {
        return Ok(DetectedAgent {
            slug: "pi_agent",
            binary_hint: Some("omp"),
            is_override: false,
            reason: "path contains .omp/agent".to_string(),
        });
    }
    if path_str.contains(".pi/agent") {
        return Ok(DetectedAgent {
            slug: "pi_agent",
            binary_hint: Some("pi"),
            is_override: false,
            reason: "path contains .pi/agent".to_string(),
        });
    }
    if path_str.contains(".gemini/") || path_str.contains("/gemini/sessions") {
        return Ok(DetectedAgent {
            slug: "gemini",
            binary_hint: None,
            is_override: false,
            reason: "path contains gemini storage".to_string(),
        });
    }

    Err(CliError {
        code: 3,
        kind: CliErrorKind::UnknownAgent.kind_str(),
        message: format!(
            "could not detect the source harness from path '{}'",
            path.display()
        ),
        hint: Some(
            "Pass --agent <name> to override (claude, codex, opencode, pi, omp, gemini).".into(),
        ),
        retryable: false,
    })
}

/// Extract a UUID-ish identifier from a session filename.
///
/// Strips a single trailing extension (`.jsonl`, `.json`, `.log`, …)
/// and returns the remaining file stem. For Claude Code and Codex this
/// IS the session UUID. Returns `None` if the path has no file stem.
fn extract_filename_session_id(path: &Path) -> Option<String> {
    path.file_stem()
        .and_then(|s| s.to_str())
        .map(|s| s.to_string())
        .filter(|s| !s.is_empty())
}

/// Best-effort check that `candidate` looks like a UUID in the canonical
/// 8-4-4-4-12 hex form (case-insensitive). Both Claude Code and Codex
/// store sessions at `<dir>/<uuid>.jsonl`, so if we extracted something
/// that clearly isn't a UUID we can surface a clearer error than the
/// "session not found" the downstream harness would emit.
fn looks_like_session_uuid(candidate: &str) -> bool {
    let bytes = candidate.as_bytes();
    if bytes.len() != 36 {
        return false;
    }
    for (i, b) in bytes.iter().enumerate() {
        match i {
            8 | 13 | 18 | 23 => {
                if *b != b'-' {
                    return false;
                }
            }
            _ => {
                if !b.is_ascii_hexdigit() {
                    return false;
                }
            }
        }
    }
    true
}

/// Extract the Oh My Pi / pi-mono session id from a JSONL session file.
///
/// Pi-agent session files begin with a `{"type":"session", ...}` header
/// that contains `id` (and often `sessionId`). We scan up to the first
/// 16 non-empty lines to find it, tolerating blank lines and leading
/// metadata. Streams line-by-line so large session logs do not get
/// read into memory in full.
///
/// A 1 MiB byte budget caps the total read so a pathologically long
/// first line (e.g. a JSONL file with no newlines, or a single megabyte
/// of garbage before the real content) cannot OOM the process. The
/// session header is always well under this budget in practice.
fn extract_pi_agent_session_id(path: &Path) -> CliResult<String> {
    use std::io::{BufRead as _, Read as _};
    const MAX_SCAN_BYTES: u64 = 1024 * 1024; // 1 MiB
    let file = std::fs::File::open(path).map_err(|err| CliError {
        code: 4,
        kind: CliErrorKind::SessionFileUnreadable.kind_str(),
        message: format!(
            "cannot open pi-agent session file {}: {err}",
            path.display()
        ),
        hint: None,
        retryable: false,
    })?;
    let reader = std::io::BufReader::new(file).take(MAX_SCAN_BYTES);
    let mut scanned = 0usize;
    for line in reader.lines() {
        let line = match line {
            Ok(l) => l,
            Err(err) => {
                // Stop at the first I/O error — the file may have been
                // truncated mid-scan, or we hit the MAX_SCAN_BYTES cap
                // in the middle of a multi-byte UTF-8 sequence. Fall
                // through to the session-id-not-found error path so
                // the user gets a clear diagnostic.
                tracing::debug!(
                    path = %path.display(),
                    error = %err,
                    "pi-agent: stopped reading after line I/O error"
                );
                break;
            }
        };
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        scanned += 1;
        if scanned > 16 {
            break;
        }
        let value: serde_json::Value = match serde_json::from_str(trimmed) {
            Ok(v) => v,
            Err(_) => continue,
        };
        // Prefer explicit `sessionId` but fall back to `id` on session-header lines.
        if let Some(id) = value.get("sessionId").and_then(|v| v.as_str()) {
            return Ok(id.to_string());
        }
        let entry_type = value.get("type").and_then(|v| v.as_str()).unwrap_or("");
        if entry_type == "session"
            && let Some(id) = value.get("id").and_then(|v| v.as_str())
        {
            return Ok(id.to_string());
        }
    }
    // Deliberately no filename fallback: pi-agent session ids come from
    // the in-file `{"type":"session","id":"..."}` header, not from the
    // filename. Synthesizing an id from the filename would produce a
    // command that looks plausible but `omp --resume` would reject with
    // a confusing error. Fail explicitly so the user knows what's wrong.
    Err(CliError {
        code: 5,
        kind: CliErrorKind::SessionIdNotFound.kind_str(),
        message: format!(
            "no session header found in pi-agent file {} (scanned first 16 non-empty lines)",
            path.display()
        ),
        hint: Some(
            "Pi-agent session ids live in the `{\"type\":\"session\",\"id\":\"...\"}` header of the JSONL file. If the file is missing its header, invoke `omp --resume <id>` directly with the id you want."
                .to_string(),
        ),
        retryable: false,
    })
}

/// Extract an OpenCode session id from a cass-stored source_path.
///
/// Cass records OpenCode conversations with
/// `source_path = <opencode.db>/<url-encoded-session-id>`, so the
/// session id is the URL-decoded final path component and the parent
/// directory's name is `opencode.db`. When `strict` is true (the
/// auto-detection path) we reject anything not matching that shape —
/// otherwise a random file under `~/.config/opencode` (such as
/// `config.json`) would produce a plausible-looking but bogus resume
/// command. When `strict` is false (the `--agent opencode` override)
/// we trust the caller and only enforce the presence of a non-empty
/// final component.
fn extract_opencode_session_id(path: &Path, strict: bool) -> CliResult<String> {
    let raw = path
        .file_name()
        .and_then(|s| s.to_str())
        .ok_or_else(|| CliError {
            code: 5,
            kind: CliErrorKind::SessionIdNotFound.kind_str(),
            message: format!("opencode path has no final component: {}", path.display()),
            hint: None,
            retryable: false,
        })?;
    if strict {
        // The parent directory must be the opencode.db virtual folder.
        // `parent_name` is the last segment of the parent path (already
        // split by the OS), so a simple equality check is both
        // sufficient and correct — no need to worry about slashes.
        let parent_name = path
            .parent()
            .and_then(|p| p.file_name())
            .and_then(|n| n.to_str());
        let looks_like_session_path = parent_name == Some("opencode.db");
        if !looks_like_session_path {
            return Err(CliError {
                code: 5,
                kind: CliErrorKind::SessionIdNotFound.kind_str(),
                message: format!(
                    "opencode session path must live under an 'opencode.db' directory, got: {}",
                    path.display()
                ),
                hint: Some(
                    "Expected path shape: '<.../opencode.db>/<session-id>' (as emitted by `cass search` and `cass sessions`). Pass `--agent opencode` to bypass this check if the id is correct."
                        .into(),
                ),
                retryable: false,
            });
        }
    }
    // Percent-decode the component. urlencoding::decode returns the
    // original string on pass-through, so this is always non-lossy.
    let decoded = urlencoding::decode(raw)
        .map(std::borrow::Cow::into_owned)
        .unwrap_or_else(|_| raw.to_string());
    if decoded.is_empty() || decoded == "opencode.db" {
        return Err(CliError {
            code: 5,
            kind: CliErrorKind::SessionIdNotFound.kind_str(),
            message: format!(
                "could not extract opencode session id from '{}'",
                path.display()
            ),
            hint: Some(
                "Expected path shape: '<opencode.db>/<session-id>' (as emitted by cass search)."
                    .into(),
            ),
            retryable: false,
        });
    }
    Ok(decoded)
}

/// Build the ready-to-run resume target for a session path. Does not
/// touch the filesystem unless the agent requires file-based id
/// extraction (pi-agent).
fn resolve_resume_target(path: &Path, agent_override: Option<&str>) -> CliResult<ResumeTarget> {
    let detected = detect_resume_agent(path, agent_override)?;
    let detection_reason = detected.reason;
    // Skip strict validations (like UUID-shape checks) when the user
    // passed `--agent ...` — explicit is explicit. We only enforce
    // strict format rules when detection came from path inference,
    // because that's the case where cass can meaningfully help the
    // user catch a "wrong path" mistake.
    let is_override = detected.is_override;

    match detected.slug {
        "claude" => {
            let uuid = extract_filename_session_id(path).ok_or_else(|| CliError {
                code: 5,
                kind: CliErrorKind::SessionIdNotFound.kind_str(),
                message: format!(
                    "cannot derive Claude Code session UUID from '{}'",
                    path.display()
                ),
                hint: None,
                retryable: false,
            })?;
            if !is_override && !looks_like_session_uuid(&uuid) {
                return Err(CliError {
                    code: 5,
                    kind: CliErrorKind::SessionIdNotFound.kind_str(),
                    message: format!(
                        "filename stem '{uuid}' does not look like a Claude Code session UUID (expected 8-4-4-4-12 hex)"
                    ),
                    hint: Some(
                        "Did you pass a project directory or notes file instead of a <uuid>.jsonl session file? Pass `--agent claude` to bypass this check if the id is correct."
                            .into(),
                    ),
                    retryable: false,
                });
            }
            Ok(ResumeTarget {
                agent: "claude",
                argv: vec!["claude".into(), "--resume".into(), uuid.clone()],
                session_id: Some(uuid),
                detection_reason,
            })
        }
        "codex" => {
            let uuid = extract_filename_session_id(path).ok_or_else(|| CliError {
                code: 5,
                kind: CliErrorKind::SessionIdNotFound.kind_str(),
                message: format!("cannot derive Codex session UUID from '{}'", path.display()),
                hint: None,
                retryable: false,
            })?;
            if !is_override && !looks_like_session_uuid(&uuid) {
                return Err(CliError {
                    code: 5,
                    kind: CliErrorKind::SessionIdNotFound.kind_str(),
                    message: format!(
                        "filename stem '{uuid}' does not look like a Codex session UUID (expected 8-4-4-4-12 hex)"
                    ),
                    hint: Some(
                        "Did you pass a date directory or log file instead of a <uuid>.jsonl session file? Pass `--agent codex` to bypass this check if the id is correct."
                            .into(),
                    ),
                    retryable: false,
                });
            }
            Ok(ResumeTarget {
                agent: "codex",
                argv: vec!["codex".into(), "resume".into(), uuid.clone()],
                session_id: Some(uuid),
                detection_reason,
            })
        }
        "opencode" => {
            // Strict mode only when we auto-detected. An explicit
            // `--agent opencode` bypasses the parent-directory check.
            let id = extract_opencode_session_id(path, !is_override)?;
            Ok(ResumeTarget {
                agent: "opencode",
                argv: vec!["opencode".into(), "resume".into(), id.clone()],
                session_id: Some(id),
                detection_reason,
            })
        }
        "pi_agent" => {
            let id = extract_pi_agent_session_id(path)?;
            // Binary selection precedence:
            //   1. Explicit override (from `--agent omp` / `--agent pi`).
            //   2. Path inference (path contains `.omp/agent` → omp).
            //   3. Fallback to `pi` (pi-mono is the original).
            let binary = detected.binary_hint.unwrap_or_else(|| {
                if path.to_string_lossy().contains(".omp/agent") {
                    "omp"
                } else {
                    "pi"
                }
            });
            Ok(ResumeTarget {
                agent: "pi_agent",
                argv: vec![binary.into(), "--resume".into(), id.clone()],
                session_id: Some(id),
                detection_reason,
            })
        }
        "gemini" => {
            // Gemini resumes by path rather than by id. Use the
            // absolute path to avoid cwd ambiguity when `cass resume`
            // is piped through another process.
            let canonical = std::fs::canonicalize(path).unwrap_or_else(|_| path.to_path_buf());
            let path_str = canonical.display().to_string();
            Ok(ResumeTarget {
                agent: "gemini",
                argv: vec![
                    "gemini".into(),
                    "session".into(),
                    "restore".into(),
                    path_str,
                ],
                session_id: None,
                detection_reason,
            })
        }
        // Unreachable: detect_resume_agent validates the slug.
        other => Err(CliError {
            code: 3,
            kind: CliErrorKind::UnknownAgent.kind_str(),
            message: format!("internal: unhandled agent slug '{other}'"),
            hint: None,
            retryable: false,
        }),
    }
}

/// `cass upgrade` — discover newer cass releases and (optionally) run
/// the same checksum-verified installer the TUI prompts to launch.
///
/// The TUI was already wired into `crate::update_check`, but the only
/// way to trigger an upgrade was to enter the TUI and respond to the
/// prompt — useless for headless / SSH / scripted environments
/// (issue #200). This subcommand re-uses every primitive already in
/// `update_check.rs`; the new code is just plumbing.
async fn run_upgrade(
    check_only: bool,
    force: bool,
    yes: bool,
    output_format: Option<RobotFormat>,
) -> CliResult<()> {
    let current = env!("CARGO_PKG_VERSION");

    // `force_check` bypasses the 1-hour cadence; otherwise honor the
    // standard interval so repeated `cass upgrade --check` invocations
    // don't hammer the GitHub API. Either way we only need a single
    // round-trip — no need to cycle through the prompt path.
    let info = if force {
        crate::update_check::force_check(current).await
    } else {
        crate::update_check::check_for_updates(current).await
    };

    // No `UpdateInfo` means: cadence skipped (only with !force), updates
    // disabled by env, or the GitHub API was unreachable. Communicate
    // each cleanly instead of pretending we're "up to date".
    let Some(info) = info else {
        if let Some(fmt) = output_format {
            let payload = serde_json::json!({
                "current_version": current,
                "latest_version": null,
                "is_newer": false,
                "is_skipped": false,
                "checked": false,
                "reason": if force {
                    "github_api_unreachable_or_disabled"
                } else {
                    "checked_recently_or_unreachable"
                },
            });
            output_structured_value(payload, fmt)?;
        } else if force {
            eprintln!(
                "Could not reach GitHub or update checks are disabled. Try again with network access."
            );
        } else {
            eprintln!(
                "No update check performed (recent check is still cached, or update checks are disabled)."
            );
            eprintln!("Re-run with `--force` to fetch the GitHub release API immediately.");
        }
        // `--check` exit semantics: 0 when there's nothing to install
        // (and we have no information saying otherwise), so this is
        // the conservative answer.
        return Ok(());
    };

    if let Some(fmt) = output_format {
        let payload = serde_json::json!({
            "current_version": current,
            "latest_version": info.latest_version,
            "tag_name": info.tag_name,
            "is_newer": info.is_newer,
            "is_skipped": info.is_skipped,
            "release_url": info.release_url,
            "checked": true,
        });
        output_structured_value(payload, fmt)?;
        if check_only && info.is_newer {
            // Mirror the documented `--check` exit-code contract.
            std::process::exit(1);
        }
        // In structured mode, only proceed to the install path when the
        // caller explicitly passed `--yes`. Anything else (no update,
        // `--check`, no `--yes` even on a TTY) returns now: prompting on
        // stdin would write y/N text on top of the JSON envelope already
        // emitted on stdout and break consumers like
        // `cass upgrade --json | jq`. Earlier the check was
        // `!yes && !is_terminal()`, which silently fell through to the
        // prompt path on an attached TTY — fixed here so structured mode
        // never prompts.
        if check_only || !info.is_newer || !yes {
            return Ok(());
        }
        // Fall through to the install path: structured mode + yes +
        // is_newer. Past this point `run_self_update` execs the
        // installer, which writes to the same stdout — but at that
        // point the caller has explicitly asked for the install side
        // effect, so the installer's output replacing the JSON envelope
        // is the documented behaviour.
    }

    if !info.is_newer {
        if output_format.is_none() {
            println!(
                "cass {current} is up to date (latest release: {}).",
                info.tag_name
            );
        }
        return Ok(());
    }

    if check_only {
        if output_format.is_none() {
            println!(
                "Update available: {current} → {}.\nView the release notes: {}",
                info.tag_name, info.release_url,
            );
        }
        // Document the contract: --check exits non-zero when an update
        // exists, so wrappers can `cass upgrade --check && echo current
        // || cass upgrade --yes`.
        std::process::exit(1);
    }

    // Decide whether to run the installer.
    let should_install = if yes {
        true
    } else if !io::stdin().is_terminal() {
        // No TTY → can't prompt → don't silently install. Tell the
        // caller exactly what to add.
        eprintln!(
            "Update available: {current} → {}, but no TTY is attached so I can't ask.\nRe-run with `--yes` to install non-interactively, or `--check` to print status.",
            info.tag_name
        );
        return Ok(());
    } else {
        print!(
            "A newer version is available: current v{}, latest {}. Update now? (y/N): ",
            current, info.tag_name
        );
        io::stdout().flush().ok();
        let mut input = String::new();
        if io::stdin().read_line(&mut input).is_err() {
            return Ok(());
        }
        matches!(input.trim(), "y" | "Y" | "yes" | "YES")
    };

    if !should_install {
        return Ok(());
    }

    info!(
        target: "upgrade",
        "starting self-update from {current} to {}",
        info.tag_name
    );
    // run_self_update returns `!` — it execs the installer over the
    // current process. Anything beyond this point is unreachable on
    // success, but reachable on a malformed version string (which the
    // function itself rejects with exit(1)).
    crate::update_check::run_self_update(&info.tag_name);
}

/// `cass resume <path>` — resolve and optionally execute the native
/// harness resume command for a session.
fn run_resume(
    path: &Path,
    agent_override: Option<&str>,
    exec: bool,
    shell: bool,
    output_format: Option<RobotFormat>,
) -> CliResult<()> {
    // Clap enforces mutual exclusion between the local flags `--exec`,
    // `--shell`, and `--json`, but it cannot see the GLOBAL
    // `--robot-format` flag from the subcommand's perspective. A user
    // doing `cass --robot-format json resume --exec /path` would
    // otherwise silently get structured output with no exec — an
    // inconsistent experience. Reject the combination explicitly so
    // the error message matches clap's own conflict errors in spirit.
    if exec && output_format.is_some() {
        return Err(CliError {
            code: 2,
            kind: CliErrorKind::Usage.kind_str(),
            message:
                "`--exec` cannot be combined with structured output (`--robot-format`/`--json`)"
                    .into(),
            hint: Some(
                "Pick one: `--exec` replaces the process with the resume command, structured output prints the plan.".into(),
            ),
            retryable: false,
        });
    }
    if shell && output_format.is_some() {
        return Err(CliError {
            code: 2,
            kind: CliErrorKind::Usage.kind_str(),
            message:
                "`--shell` cannot be combined with structured output (`--robot-format`/`--json`)"
                    .into(),
            hint: Some(
                "Pick one: `--shell` emits a shell-escaped command line, structured output emits a JSON object.".into(),
            ),
            retryable: false,
        });
    }

    let target = resolve_resume_target(path, agent_override)?;

    // Output mode precedence (mutually exclusive by construction above):
    //   1. structured output (`--robot-format json|yaml|msgpack`, `--json`)
    //   2. `--exec` — replaces the process, side-effectful
    //   3. `--shell` — single quoted command line
    //   4. Default — one argv token per line
    if let Some(fmt) = output_format {
        let payload = serde_json::json!({
            "success": true,
            "agent": target.agent,
            "session_id": target.session_id,
            "command": target.argv,
            "shell_command": target
                .argv
                .iter()
                .map(|a| shell_quote(a))
                .collect::<Vec<_>>()
                .join(" "),
            "detection": target.detection_reason,
            "path": path.display().to_string(),
        });
        output_structured_value(payload, fmt)?;
        return Ok(());
    }

    if exec {
        // Replace the current process with the resume command so the
        // caller's TTY is handed over to the resumed harness cleanly.
        let (program, args) = target.argv.split_first().ok_or_else(|| CliError {
            code: 6,
            kind: CliErrorKind::ResumeEmptyCommand.kind_str(),
            message: "internal: resolved resume command had no program".into(),
            hint: None,
            retryable: false,
        })?;
        #[cfg(unix)]
        {
            use std::os::unix::process::CommandExt as _;
            let err = std::process::Command::new(program).args(args).exec();
            // `exec` only returns on failure.
            return Err(CliError {
                code: 7,
                kind: CliErrorKind::ResumeExecFailed.kind_str(),
                message: format!("failed to exec '{program}': {err}"),
                hint: Some(format!(
                    "Verify that '{program}' is installed and on your PATH."
                )),
                retryable: false,
            });
        }
        #[cfg(not(unix))]
        {
            let status = std::process::Command::new(program)
                .args(args)
                .status()
                .map_err(|err| CliError {
                    code: 7,
                    kind: CliErrorKind::ResumeExecFailed.kind_str(),
                    message: format!("failed to spawn '{program}': {err}"),
                    hint: None,
                    retryable: false,
                })?;
            std::process::exit(status.code().unwrap_or(1));
        }
    }

    if shell {
        // Single-line shell-quoted command for `eval "$(cass resume ...)"`.
        let line = target
            .argv
            .iter()
            .map(|a| shell_quote(a))
            .collect::<Vec<_>>()
            .join(" ");
        println!("{line}");
        return Ok(());
    }

    // Default: one argv token per line. Lets callers either `xargs`
    // the output or read it into a shell array without extra parsing.
    for token in &target.argv {
        println!("{token}");
    }
    Ok(())
}

/// Export a conversation to markdown or other formats
#[allow(clippy::too_many_arguments)]
fn run_export(
    path: &Path,
    db_override: Option<PathBuf>,
    source_id: Option<&str>,
    format: ConvExportFormat,
    output: Option<&Path>,
    clipboard: bool,
    include_tools: bool,
    include_skills: bool,
) -> CliResult<()> {
    use std::fs::File;
    use std::io::Write;

    if let Some(source_id) = source_id {
        validate_followup_source_id(source_id, "cass export")?;
    }
    let normalized_source_id = canonical_followup_source_id(source_id);
    let source_id = normalized_source_id.as_deref();

    let db_path = db_override.unwrap_or_else(default_db_path);
    let allow_direct_file = followup_source_is_local(source_id) || source_id.is_none();
    let mut indexed_view = if should_defer_indexed_lookup_for_direct_export(path, source_id) {
        None
    } else {
        try_load_indexed_conversation_from_db_with_source(path, &db_path, source_id)
    };

    if source_id.is_none()
        && !path_exists_or_virtual_opencode_sqlite_session(path, allow_direct_file)
        && indexed_view.is_none()
    {
        return Err(CliError {
            code: 3,
            kind: CliErrorKind::FileNotFound.kind_str(),
            message: format!("Session file not found: {}", path.display()),
            hint: Some("Use 'cass search' to find session paths".to_string()),
            retryable: false,
        });
    }

    let mut messages: Vec<serde_json::Value>;
    let indexed_title = indexed_view
        .as_ref()
        .and_then(|view| view.convo.title.clone());
    let mut session_title: Option<String> = indexed_title;
    let session_start: Option<i64>;
    let mut _session_end: Option<i64>;
    let prefer_direct_file = prefers_direct_jsonl_file(path, source_id);

    if prefer_direct_file {
        match parse_followup_jsonl_messages(path) {
            Ok((parsed_messages, parsed_start, parsed_end)) => {
                messages = parsed_messages;
                session_start = parsed_start;
                _session_end = parsed_end;
            }
            Err(err) => {
                if indexed_view.is_none() {
                    indexed_view = try_load_indexed_conversation_from_db_with_source(
                        path, &db_path, source_id,
                    );
                }
                if let Some(view) = indexed_view.as_ref() {
                    session_title = view.convo.title.clone();
                    session_start = view.convo.started_at;
                    _session_end = view.convo.ended_at;
                    messages = conversation_view_to_raw_messages(view);
                } else {
                    return Err(err);
                }
            }
        }
    } else if let Some(view) = indexed_view.as_ref() {
        session_title = view.convo.title.clone();
        session_start = view.convo.started_at;
        _session_end = view.convo.ended_at;
        messages = conversation_view_to_raw_messages(view);
    } else if allow_direct_file && detect_opencode_sqlite_session(path) {
        // OpenCode SQLite-backed session: path is db_path/session_id (#149)
        match load_opencode_sqlite_session_for_export(path) {
            Ok((title, start, end, msgs)) => {
                session_title = title;
                session_start = start;
                _session_end = end;
                messages = msgs;
            }
            Err(e) => {
                return Err(CliError {
                    code: 9,
                    kind: CliErrorKind::OpencodeSqliteParse.kind_str(),
                    message: format!("Failed to load OpenCode SQLite session: {e}"),
                    hint: Some(
                        "Ensure the OpenCode database exists and the session ID is valid".into(),
                    ),
                    retryable: false,
                });
            }
        }
    } else if allow_direct_file && detect_opencode_session(path) {
        match load_opencode_session_for_export(path) {
            Ok((title, start, end, msgs)) => {
                session_title = title;
                session_start = start;
                _session_end = end;
                messages = msgs;
            }
            Err(e) => {
                return Err(CliError {
                    code: 9,
                    kind: CliErrorKind::OpencodeParse.kind_str(),
                    message: format!("Failed to parse OpenCode session: {e}"),
                    hint: Some(
                        "Ensure the session file is valid and message/part directories exist"
                            .into(),
                    ),
                    retryable: false,
                });
            }
        }
    } else if allow_direct_file && path.exists() {
        if prefers_direct_jsonl_file(path, source_id) {
            let (parsed_messages, parsed_start, parsed_end) = parse_followup_jsonl_messages(path)?;
            messages = parsed_messages;
            session_start = parsed_start;
            _session_end = parsed_end;
        } else {
            return Err(CliError {
                code: 9,
                kind: CliErrorKind::IndexedSessionRequired.kind_str(),
                message: format!(
                    "Local export for '{}' requires an indexed conversation or a JSONL/OpenCode session",
                    path.display()
                ),
                hint: Some(
                    "Run 'cass index --full' first, or export directly from a JSONL/OpenCode session."
                        .to_string(),
                ),
                retryable: false,
            });
        }
    } else {
        return Err(CliError {
            code: 3,
            kind: CliErrorKind::FileNotFound.kind_str(),
            message: match source_id {
                Some(source_id) => format!(
                    "No indexed session found for source '{}' at {}",
                    source_id,
                    path.display()
                ),
                None => format!("Session file not found: {}", path.display()),
            },
            hint: Some(match source_id {
                Some(_) => {
                    "Use the exact source_id from search output or omit --source to prefer the local file/path."
                        .to_string()
                }
                None => "Use 'cass search' to find session paths".to_string(),
            }),
            retryable: false,
        });
    }

    if !include_skills {
        messages.retain(|msg| {
            let content = extract_text_content(msg);
            if content.contains("Base directory for this skill:") {
                return false;
            }
            if content.contains("<system-reminder>") {
                return false;
            }
            if content.contains("The following skills are available for use with the Skill tool:") {
                return false;
            }
            if content.contains("skillInjection:") && content.contains("matchedSkills") {
                return false;
            }
            if content.contains("<!-- skillInjection:") {
                return false;
            }
            true
        });
    }

    if messages.is_empty() {
        return Err(CliError {
            code: 9,
            kind: CliErrorKind::EmptySession.kind_str(),
            message: format!("No messages found in: {}", path.display()),
            hint: if allow_direct_file && detect_opencode_sqlite_session(path) {
                Some("This path references an OpenCode SQLite session. Use `cass sessions --json` to list available sessions and their exportable paths.".into())
            } else if allow_direct_file && detect_opencode_session(path) {
                Some("Check that storage/message/{sessionID}/ contains message files".into())
            } else {
                None
            },
            retryable: false,
        });
    }

    if session_title.is_none() {
        for msg in &messages {
            let role = extract_role(msg);
            if role == "user" {
                let content = extract_text_content(msg);
                if !content.is_empty() {
                    let first_line = content.lines().next().unwrap_or("Untitled Session");
                    session_title = Some(smart_truncate(first_line, 80));
                    break;
                }
            }
        }
    }

    let formatted = match format {
        ConvExportFormat::Markdown => {
            format_as_markdown(&messages, &session_title, session_start, include_tools)
        }
        ConvExportFormat::Text => format_as_text(&messages, include_tools),
        ConvExportFormat::Json => serde_json::to_string_pretty(&messages).unwrap_or_default(),
        ConvExportFormat::Html => {
            format_as_html(&messages, &session_title, session_start, include_tools)
        }
    };

    if let Some(out_path) = output {
        let mut out_file = File::create(out_path).map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::FileCreate.kind_str(),
            message: format!("Failed to create output file: {e}"),
            hint: None,
            retryable: false,
        })?;
        out_file
            .write_all(formatted.as_bytes())
            .map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::FileWrite.kind_str(),
                message: format!("Failed to write output: {e}"),
                hint: None,
                retryable: false,
            })?;
        println!("Exported to: {}", out_path.display());
    } else if clipboard {
        match copy_to_system_clipboard(&formatted) {
            Ok(tool) => {
                let bytes = formatted.len();
                eprintln!(
                    "Copied {bytes} bytes to clipboard via {tool}. Paste into your coding agent's chat to resume the conversation."
                );
            }
            Err(err) => {
                // Headless/SSH and similar — fall back to stdout so the
                // caller still gets the export, but make the failure
                // legible on stderr so a wrapper script knows clipboard
                // handoff didn't happen.
                eprintln!("warning: clipboard not available ({err}); falling back to stdout.");
                println!("{formatted}");
            }
        }
    } else {
        println!("{formatted}");
    }

    Ok(())
}

/// Stream `text` into the system clipboard by spawning the platform's
/// canonical clipboard tool. Returns the name of the tool used on success.
///
/// Used by `cass export --clipboard` so users can hand a freshly-found
/// thread into their coding agent (Cursor, Claude Code, …) with one
/// keystroke. Shells out instead of taking a clipboard-crate dependency
/// because (a) no current dep covers all four targets we care about and
/// (b) the sub-process approach degrades cleanly to the stdout fallback
/// when no tool is on PATH (headless servers, SSH sessions).
fn copy_to_system_clipboard(text: &str) -> Result<&'static str, String> {
    use std::io::Write;
    use std::process::{Command, Stdio};

    // (program, args). First match wins. Order matters on Linux:
    // Wayland sessions ignore X11 selections, so wl-copy must be tried
    // before xclip / xsel even though the latter are more common.
    let candidates: &[(&str, &[&str])] = if cfg!(target_os = "macos") {
        &[("pbcopy", &[])]
    } else if cfg!(target_os = "windows") {
        &[("clip", &[])]
    } else {
        &[
            ("wl-copy", &[]),
            ("xclip", &["-selection", "clipboard"]),
            ("xsel", &["--clipboard", "--input"]),
        ]
    };

    let mut last_err: Option<String> = None;
    for (program, args) in candidates {
        // IMPORTANT: stdout / stderr go to /dev/null rather than piped.
        // Linux clipboard tools (wl-copy, xclip, xsel) fork a daemon
        // that holds the X11 / Wayland selection until the clipboard
        // is replaced or the session ends. The parent exits as soon as
        // stdin is closed, but the daemon inherits the parent's fds.
        // If we piped stdout/stderr, `wait_with_output` would block
        // forever waiting for those pipes to reach EOF — which only
        // happens when the daemon dies, possibly minutes or hours later.
        // /dev/null avoids that without requiring a separate reader
        // thread or a tool-specific "no fork" flag (which not all of
        // them expose).
        let spawn_result = Command::new(program)
            .args(args.iter().copied())
            .stdin(Stdio::piped())
            .stdout(Stdio::null())
            .stderr(Stdio::null())
            .spawn();
        let mut child = match spawn_result {
            Ok(c) => c,
            Err(e) => {
                // ENOENT etc.: tool not installed, try the next candidate.
                last_err = Some(format!("{program}: {e}"));
                continue;
            }
        };
        // Take stdin and drop it via a scoped block so the write end of
        // the pipe is closed *before* we wait — otherwise the child
        // sits in `read(stdin)` forever and so do we.
        let write_result = {
            let mut stdin = match child.stdin.take() {
                Some(s) => s,
                None => {
                    last_err = Some(format!("{program}: stdin pipe missing"));
                    let _ = child.wait();
                    continue;
                }
            };
            stdin.write_all(text.as_bytes())
        };
        if let Err(e) = write_result {
            last_err = Some(format!("{program}: write stdin: {e}"));
            let _ = child.wait();
            continue;
        }
        // `wait` returns as soon as the parent exits, even if a
        // backgrounded daemon child keeps running with the inherited
        // (now /dev/null) stdout / stderr.
        match child.wait() {
            Ok(status) if status.success() => return Ok(program),
            Ok(status) => {
                last_err = Some(format!("{program} exited with status {status}"));
            }
            Err(e) => {
                last_err = Some(format!("{program}: wait: {e}"));
            }
        }
    }

    let tried = candidates
        .iter()
        .map(|(p, _)| *p)
        .collect::<Vec<_>>()
        .join(", ");
    Err(match last_err {
        Some(detail) => {
            format!("no clipboard tool succeeded (tried {tried}; last error: {detail})")
        }
        None => format!("no clipboard tool found on PATH (tried {tried})"),
    })
}

fn strip_stdin_line_ending(mut input: String) -> String {
    while input.ends_with('\n') || input.ends_with('\r') {
        input.pop();
    }
    input
}

#[cfg(test)]
mod export_html_password_tests {
    use super::strip_stdin_line_ending;

    #[test]
    fn stdin_password_preserves_significant_surrounding_space() {
        assert_eq!(
            strip_stdin_line_ending("  pass phrase  \n".to_string()),
            "  pass phrase  "
        );
        assert_eq!(
            strip_stdin_line_ending("\tpass phrase\t\r\n".to_string()),
            "\tpass phrase\t"
        );
    }
}

#[cfg(test)]
mod clipboard_helper_tests {
    use super::copy_to_system_clipboard;

    /// On a host with **no** clipboard tool on PATH (PATH=""), the helper
    /// must return Err so the caller can fall back to stdout. The
    /// previous failure mode was a silent success that dropped the
    /// export on the floor.
    #[test]
    fn returns_err_when_no_tool_is_available() {
        // Save and clear PATH so spawn() can't find pbcopy/wl-copy/xclip
        // /xsel/clip. Restore on exit even if the assertion panics.
        struct PathGuard(Option<std::ffi::OsString>);
        impl Drop for PathGuard {
            fn drop(&mut self) {
                // Tests touch process env: required for an end-to-end
                // check of the spawn fallback chain.
                unsafe {
                    match self.0.take() {
                        Some(prev) => std::env::set_var("PATH", prev),
                        None => std::env::remove_var("PATH"),
                    }
                }
            }
        }
        let guard = PathGuard(std::env::var_os("PATH"));
        unsafe {
            std::env::set_var("PATH", "");
        }

        let err = copy_to_system_clipboard("hello")
            .expect_err("with PATH cleared, no clipboard tool should be findable");
        assert!(
            err.contains("no clipboard tool") || err.contains("tried"),
            "error should describe what was tried, got: {err}"
        );

        drop(guard);
    }
}

/// Export a session as a beautiful, self-contained HTML file with optional encryption.
#[allow(clippy::too_many_arguments)]
fn run_export_html(
    session_path: &Path,
    db_override: Option<PathBuf>,
    source_id: Option<&str>,
    output_dir: Option<&Path>,
    filename: Option<&str>,
    encrypt: bool,
    password_stdin: bool,
    include_tools: bool,
    show_timestamps: bool,
    enable_cdns: bool,
    include_skills: bool,
    theme: &str,
    dry_run: bool,
    explain: bool,
    open: bool,
    output_format: Option<RobotFormat>,
) -> CliResult<()> {
    use chrono::TimeZone;
    use html_export::{
        ExportOptions as HtmlExportOptions, HtmlExporter, Message, TemplateMetadata,
        generate_full_filename, get_downloads_dir, is_valid_filename,
    };
    use std::fs::File;
    use std::io::{self, Write};

    if let Some(source_id) = source_id {
        validate_followup_source_id(source_id, "cass export-html")?;
    }
    let normalized_source_id = canonical_followup_source_id(source_id);
    let source_id = normalized_source_id.as_deref();
    let structured_error_output = output_format.or_else(robot_format_from_env).is_some();
    let emit_structured_error = |err: &CliError| {
        if structured_error_output {
            println!(
                "{}",
                serde_json::json!({
                    "success": false,
                    "error": {
                        "code": err.code,
                        "kind": err.kind,
                        "message": err.message,
                        "hint": err.hint,
                        "retryable": err.retryable
                    }
                })
            );
        }
    };

    let db_path = db_override.unwrap_or_else(default_db_path);
    let allow_direct_file = followup_source_is_local(source_id) || source_id.is_none();
    let mut indexed_view = if should_defer_indexed_lookup_for_direct_export(session_path, source_id)
    {
        None
    } else {
        try_load_indexed_conversation_from_db_with_source(session_path, &db_path, source_id)
    };

    // --- Validate session exists ---
    if indexed_view.is_none()
        && !path_exists_or_virtual_opencode_sqlite_session(session_path, allow_direct_file)
    {
        let err = CliError {
            code: 3,
            kind: CliErrorKind::SessionNotFound.kind_str(),
            message: match source_id {
                Some(source_id) => format!(
                    "No indexed session found for source '{}' at {}",
                    source_id,
                    session_path.display()
                ),
                None => format!("Session file not found: {}", session_path.display()),
            },
            hint: Some(match source_id {
                Some(_) => "Use the exact source_id from search output or omit --source to prefer the local file/path.".to_string(),
                None => "Use 'cass search' to find session paths".to_string(),
            }),
            retryable: false,
        };
        let structured_format = output_format.or_else(robot_format_from_env).map(|fmt| {
            if matches!(fmt, RobotFormat::Sessions) {
                RobotFormat::Compact
            } else {
                fmt
            }
        });

        if let Some(_fmt) = structured_format {
            println!(
                "{}",
                serde_json::json!({
                    "success": false,
                    "error": {
                        "code": err.code,
                        "kind": err.kind,
                        "message": err.message,
                        "hint": err.hint,
                        "retryable": err.retryable
                    }
                })
            );
            return Err(err);
        }
        return Err(err);
    }

    // --- Get password if encryption requested ---
    let final_password: Option<String> = if encrypt {
        if password_stdin {
            let mut pwd = String::new();
            io::stdin().read_line(&mut pwd).map_err(|e| CliError {
                code: 6,
                kind: CliErrorKind::PasswordReadError.kind_str(),
                message: format!("Failed to read password from stdin: {e}"),
                hint: None,
                retryable: false,
            })?;
            Some(strip_stdin_line_ending(pwd))
        } else {
            let err = CliError {
                code: 6,
                kind: CliErrorKind::PasswordRequired.kind_str(),
                message: "Password required for encryption".to_string(),
                hint: Some("Use --password-stdin".to_string()),
                retryable: false,
            };
            let structured_format = output_format.or_else(robot_format_from_env).map(|fmt| {
                if matches!(fmt, RobotFormat::Sessions) {
                    RobotFormat::Compact
                } else {
                    fmt
                }
            });

            if let Some(_fmt) = structured_format {
                println!(
                    "{}",
                    serde_json::json!({
                        "success": false,
                        "error": {
                            "code": err.code,
                            "kind": err.kind,
                            "message": err.message,
                            "hint": err.hint,
                            "retryable": err.retryable
                        }
                    })
                );
            }
            return Err(err);
        }
    } else {
        None
    };

    // --- Load session messages ---
    let raw_messages: Vec<serde_json::Value>;
    let indexed_title = indexed_view
        .as_ref()
        .and_then(|view| view.convo.title.clone());
    let indexed_agent_name = indexed_view
        .as_ref()
        .map(|view| view.convo.agent_slug.clone());
    let indexed_workspace = indexed_view.as_ref().and_then(|view| {
        view.convo
            .workspace
            .as_ref()
            .map(|path| path.display().to_string())
    });
    let (path_agent_name, path_workspace) = infer_followup_agent_and_workspace(session_path);
    let mut session_title: Option<String> = indexed_title;
    let session_start: Option<i64>;
    let session_end: Option<i64>;
    let mut agent_name: Option<String> = indexed_agent_name.or(path_agent_name);
    let mut workspace: Option<String> = indexed_workspace.or(path_workspace);
    let prefer_direct_file = prefers_direct_jsonl_file(session_path, source_id);

    if prefer_direct_file {
        match parse_followup_jsonl_messages(session_path) {
            Ok((parsed_messages, parsed_start, parsed_end)) => {
                raw_messages = parsed_messages;
                session_start = parsed_start;
                session_end = parsed_end;
            }
            Err(err) => {
                if indexed_view.is_none() {
                    indexed_view = try_load_indexed_conversation_from_db_with_source(
                        session_path,
                        &db_path,
                        source_id,
                    );
                }
                if let Some(view) = indexed_view.as_ref() {
                    session_title = view.convo.title.clone();
                    session_start = view.convo.started_at;
                    session_end = view.convo.ended_at;
                    agent_name = Some(view.convo.agent_slug.clone());
                    workspace = view
                        .convo
                        .workspace
                        .as_ref()
                        .map(|p| p.display().to_string());
                    raw_messages = conversation_view_to_raw_messages(view);
                } else {
                    emit_structured_error(&err);
                    return Err(err);
                }
            }
        }
    } else if let Some(view) = indexed_view.as_ref() {
        session_title = view.convo.title.clone();
        session_start = view.convo.started_at;
        session_end = view.convo.ended_at;
        agent_name = Some(view.convo.agent_slug.clone());
        workspace = view
            .convo
            .workspace
            .as_ref()
            .map(|p| p.display().to_string());
        raw_messages = conversation_view_to_raw_messages(view);
    } else {
        // Detect agent from path
        let path_str = session_path.to_string_lossy();
        let path_lower = path_str.to_ascii_lowercase();
        if path_lower.contains(".claude") {
            agent_name = Some("claude_code".to_string());
        } else if path_lower.contains(".codex") {
            agent_name = Some("codex".to_string());
        } else if path_lower.contains("cursor") {
            agent_name = Some("cursor".to_string());
        } else if path_lower.contains(".gemini") {
            agent_name = Some("gemini".to_string());
        } else if path_lower.contains(".vibe") {
            agent_name = Some("vibe".to_string());
        }

        // Extract workspace from path
        if let Some(parent) = session_path.parent() {
            workspace = Some(parent.display().to_string());
        }

        if allow_direct_file && detect_opencode_sqlite_session(session_path) {
            // OpenCode SQLite-backed session: path is db_path/session_id (#149)
            match load_opencode_sqlite_session_for_export(session_path) {
                Ok((title, start, end, msgs)) => {
                    session_title = title;
                    session_start = start;
                    session_end = end;
                    raw_messages = msgs;
                    agent_name = Some("opencode".to_string());
                }
                Err(e) => {
                    let err = CliError {
                        code: 9,
                        kind: CliErrorKind::OpencodeSqliteParse.kind_str(),
                        message: format!("Failed to load OpenCode SQLite session: {e}"),
                        hint: Some(
                            "Ensure the OpenCode database exists and the session ID is valid"
                                .into(),
                        ),
                        retryable: false,
                    };
                    emit_structured_error(&err);
                    return Err(err);
                }
            }
        } else if allow_direct_file && detect_opencode_session(session_path) {
            match load_opencode_session_for_export(session_path) {
                Ok((title, start, end, msgs)) => {
                    session_title = title;
                    session_start = start;
                    session_end = end;
                    raw_messages = msgs;
                    agent_name = Some("opencode".to_string());
                }
                Err(e) => {
                    let err = CliError {
                        code: 9,
                        kind: CliErrorKind::OpencodeParse.kind_str(),
                        message: format!("Failed to parse OpenCode session: {e}"),
                        hint: Some("Ensure the session file is valid".into()),
                        retryable: false,
                    };
                    emit_structured_error(&err);
                    return Err(err);
                }
            }
        } else if prefers_direct_jsonl_file(session_path, source_id) {
            let (parsed_messages, parsed_start, parsed_end) =
                parse_followup_jsonl_messages(session_path).inspect_err(|err| {
                    emit_structured_error(err);
                })?;
            raw_messages = parsed_messages;
            session_start = parsed_start;
            session_end = parsed_end;
        } else {
            let err = CliError {
                code: 9,
                kind: CliErrorKind::IndexedSessionRequired.kind_str(),
                message: format!(
                    "Local export for '{}' requires an indexed conversation or a JSONL/OpenCode session",
                    session_path.display()
                ),
                hint: Some(
                    "Run 'cass index --full' first, or export directly from a JSONL/OpenCode session."
                        .to_string(),
                ),
                retryable: false,
            };
            emit_structured_error(&err);
            return Err(err);
        }
    }

    if raw_messages.is_empty() {
        let err = CliError {
            code: 9,
            kind: CliErrorKind::EmptySession.kind_str(),
            message: format!("No messages found in: {}", session_path.display()),
            hint: None,
            retryable: false,
        };
        emit_structured_error(&err);
        return Err(err);
    }

    // Find title from first user message
    if session_title.is_none() {
        for msg in &raw_messages {
            let role = extract_role(msg);
            if role == "user" {
                let content = extract_text_content(msg);
                if !content.is_empty() {
                    let first_line = content.lines().next().unwrap_or("Untitled Session");
                    session_title = Some(smart_truncate(first_line, 80));
                    break;
                }
            }
        }
    }

    // --- Convert to renderer::Message format (filtering empty messages) ---
    let messages: Vec<Message> = raw_messages
        .iter()
        .enumerate()
        .filter_map(|(i, msg)| {
            let role = extract_role(msg);
            let content = extract_text_content(msg);
            let ts = extract_message_timestamp(msg);
            let timestamp = ts
                .and_then(|ts| chrono::Utc.timestamp_millis_opt(ts).single())
                .map(|dt| dt.to_rfc3339());

            // Extract tool call info if present
            let tool_call = if include_tools {
                extract_tool_call(msg)
            } else {
                None
            };

            // If we have a tool_call, strip the redundant "[Tool: X]" prefix from content
            // since the tool call details are shown separately in the HTML export
            let content = if tool_call.is_some() {
                strip_tool_marker(&content)
            } else {
                content
            };

            // --- Drop entire messages that are skill injections (unless opted in) ---
            // When Claude Code/Codex/Gemini load a skill, the FULL SKILL.md body is
            // injected as a user message starting with "Base directory for this skill:".
            // These are often highly proprietary. DROP THE ENTIRE MESSAGE — don't try
            // to parse, redact, or pattern-match the content. Just skip it.
            if !include_skills {
                if content.contains("Base directory for this skill:") {
                    return None;
                }
                // System reminders contain skill listings, hook metadata, and other
                // internal context. Drop entire messages that are system-reminder blocks.
                if content.contains("<system-reminder>") {
                    return None;
                }
                // Skill listing dumps (injected by hooks)
                if content
                    .contains("The following skills are available for use with the Skill tool:")
                {
                    return None;
                }
                // Vercel plugin hook injections with skill metadata
                if content.contains("skillInjection:") && content.contains("matchedSkills") {
                    return None;
                }
                // Hook injection blocks (contain skill names, patterns, metadata)
                if content.contains("<!-- skillInjection:") {
                    return None;
                }
            }

            // Skip non-message records (queue-operation, summary, etc.)
            // These are internal bookkeeping entries, not actual conversation messages.
            // Only user, assistant, system, tool, and unknown are valid message roles.
            match role.as_str() {
                "user" | "assistant" | "system" | "tool" | "unknown" => {}
                _ => return None,
            }

            // Skip empty messages: no content AND no tool call AND unknown role
            // This filters out malformed/empty entries that would look broken
            if content.is_empty() && tool_call.is_none() && role == "unknown" {
                return None;
            }

            // Also skip messages that are completely empty (no content, no tool call)
            // but keep tool calls even if content is empty (shows the tool interaction)
            if content.is_empty() && tool_call.is_none() {
                return None;
            }

            Some(Message {
                role,
                content,
                timestamp,
                tool_call,
                index: Some(i),
                author: None,
            })
        })
        .collect();

    // Count message types from RAW messages for accuracy.
    // Must distinguish human-typed prompts from tool results, which both have role "user".
    // Tool results have content as an array containing {"type": "tool_result", ...} blocks.
    // Also exclude skill injections from counts when !include_skills, since those messages
    // are dropped from the rendered output and shouldn't inflate the prompt count.
    let mut human_turns = 0usize;
    let mut assistant_msgs = 0usize;
    let mut tool_use_count = 0usize;
    for msg in &raw_messages {
        let role = extract_role(msg);
        let text = extract_text_content(msg);

        // Skip messages that would be dropped by skill filtering
        if !include_skills
            && (text.contains("Base directory for this skill:")
                || text.contains("<system-reminder>")
                || text.contains("The following skills are available for use with the Skill tool:")
                || (text.contains("skillInjection:") && text.contains("matchedSkills"))
                || text.contains("<!-- skillInjection:"))
        {
            continue;
        }

        match role.as_str() {
            "user" => {
                // Check if this is a tool result return or a human-typed message.
                // Tool results have content as an array with tool_result type blocks.
                let is_tool_result = msg
                    .get("message")
                    .or(Some(msg))
                    .and_then(|m| m.get("content"))
                    .and_then(|c| c.as_array())
                    .is_some_and(|arr| {
                        arr.iter().any(|item| {
                            item.get("type").and_then(|t| t.as_str()) == Some("tool_result")
                        })
                    });
                if !is_tool_result {
                    human_turns += 1;
                }
            }
            "assistant" => {
                assistant_msgs += 1;
                // Count tool_use blocks within assistant messages
                if let Some(content) = msg
                    .get("message")
                    .or(Some(msg))
                    .and_then(|m| m.get("content"))
                    .and_then(|c| c.as_array())
                {
                    tool_use_count += content
                        .iter()
                        .filter(|item| {
                            item.get("type").and_then(|t| t.as_str()) == Some("tool_use")
                        })
                        .count();
                }
            }
            _ => {}
        }
    }
    let message_count = messages.len();

    // --- Build metadata ---
    let duration = match (session_start, session_end) {
        (Some(start), Some(end)) if end > start => {
            let mins = (end - start) / 60_000;
            if mins >= 60 {
                Some(format!("{}h {}m", mins / 60, mins % 60))
            } else if mins > 0 {
                Some(format!("{}m", mins))
            } else {
                Some("< 1m".to_string())
            }
        }
        _ => None,
    };

    let metadata = TemplateMetadata {
        timestamp: session_start.map(|ts| {
            chrono::Utc
                .timestamp_millis_opt(ts)
                .single()
                .map(|dt| dt.format("%Y-%m-%d %H:%M UTC").to_string())
                .unwrap_or_default()
        }),
        agent: agent_name.clone(),
        message_count,
        human_turns,
        assistant_msgs,
        tool_use_count,
        duration,
        project: workspace.clone(),
    };

    // --- Generate output path ---
    let output_directory = output_dir
        .map(|p| p.to_path_buf())
        .unwrap_or_else(get_downloads_dir);

    let workspace_path = workspace.as_deref().map(Path::new);

    let mut final_filename = if let Some(name) = filename {
        name.to_string()
    } else {
        generate_full_filename(
            agent_name.as_deref().unwrap_or("cass"),
            workspace_path,
            session_start,
            session_title.as_deref(),
            session_title.as_deref(),
        )
    };

    if Path::new(&final_filename).extension().is_none() {
        final_filename.push_str(".html");
    }

    if filename.is_some() && !is_valid_filename(&final_filename) {
        let err = CliError {
            code: 4,
            kind: CliErrorKind::InvalidFilename.kind_str(),
            message: format!("Invalid output filename: {final_filename}"),
            hint: Some("Avoid path separators and reserved characters".to_string()),
            retryable: false,
        };
        emit_structured_error(&err);
        return Err(err);
    }

    let output_path = output_directory.join(final_filename);

    // Estimate file size (rough: 200 bytes per message + overhead)
    let estimated_size = message_count * 200 + 15000;

    // --- Explain mode ---
    if explain {
        let plan = serde_json::json!({
            "plan": {
                "session_path": session_path.display().to_string(),
                "agent": agent_name,
                "messages": message_count,
                "output_path": output_path.display().to_string(),
                "estimated_size_bytes": estimated_size,
                "options": {
                    "encrypted": encrypt,
                    "include_tools": include_tools,
                    "show_timestamps": show_timestamps,
                    "cdns_enabled": enable_cdns,
                    "default_theme": theme
                }
            },
            "warnings": []
        });
        println!(
            "{}",
            serde_json::to_string_pretty(&plan).unwrap_or_else(|_| "{}".to_string())
        );
        return Ok(());
    }

    // --- Dry run mode ---
    if dry_run {
        let result = serde_json::json!({
            "dry_run": true,
            "valid": true,
            "session_path": session_path.display().to_string(),
            "output_path": output_path.display().to_string(),
            "messages": message_count,
            "encrypted": encrypt,
            "estimated_size_bytes": estimated_size
        });
        println!(
            "{}",
            serde_json::to_string_pretty(&result).unwrap_or_else(|_| "{}".to_string())
        );
        return Ok(());
    }

    // --- Build export options ---
    let export_options = HtmlExportOptions {
        title: session_title.clone(),
        include_cdn: enable_cdns,
        syntax_highlighting: true,
        include_search: true,
        include_theme_toggle: true,
        encrypt,
        print_styles: true,
        agent_name: agent_name.clone(),
        show_timestamps,
        show_tool_calls: include_tools,
    };

    // --- Export ---
    let exporter = HtmlExporter::with_options(export_options);
    let title = session_title.as_deref().unwrap_or("Conversation Export");

    // Group messages for consolidated rendering (tool calls with parent messages)
    let message_groups = group_messages_for_export(messages);

    let html = exporter
        .export_messages(title, &message_groups, metadata, final_password.as_deref())
        .map_err(|e| {
            let err = CliError {
                code: 5,
                kind: CliErrorKind::ExportFailed.kind_str(),
                message: format!("Failed to export HTML: {e}"),
                hint: None,
                retryable: false,
            };
            emit_structured_error(&err);
            err
        })?;

    // --- Write file ---
    std::fs::create_dir_all(output_path.parent().unwrap_or(Path::new("."))).ok();
    let mut file = File::create(&output_path).map_err(|e| {
        let err = CliError {
            code: 4,
            kind: CliErrorKind::OutputNotWritable.kind_str(),
            message: format!("Could not create output file: {e}"),
            hint: Some(format!(
                "Check permissions for {}",
                output_directory.display()
            )),
            retryable: false,
        };
        emit_structured_error(&err);
        err
    })?;
    file.write_all(html.as_bytes()).map_err(|e| {
        let err = CliError {
            code: 4,
            kind: CliErrorKind::WriteFailed.kind_str(),
            message: format!("Failed to write file: {e}"),
            hint: None,
            retryable: false,
        };
        emit_structured_error(&err);
        err
    })?;

    let file_size = html.len();

    // --- Open in browser if requested ---
    if open {
        #[cfg(target_os = "macos")]
        {
            let _ = std::process::Command::new("open").arg(&output_path).spawn();
        }
        #[cfg(target_os = "linux")]
        {
            let _ = std::process::Command::new("xdg-open")
                .arg(&output_path)
                .spawn();
        }
        #[cfg(target_os = "windows")]
        {
            let _ = std::process::Command::new("explorer")
                .arg(&output_path)
                .spawn();
        }
    }

    // --- Output result ---
    let structured_format = output_format.or_else(robot_format_from_env).map(|fmt| {
        if matches!(fmt, RobotFormat::Sessions) {
            RobotFormat::Compact
        } else {
            fmt
        }
    });

    if let Some(_fmt) = structured_format {
        let result = serde_json::json!({
            "success": true,
            "exported": {
                "session_path": session_path.display().to_string(),
                "output_path": output_path.display().to_string(),
                "filename": output_path.file_name().map(|n| n.to_string_lossy().to_string()),
                "size_bytes": file_size,
                "encrypted": encrypt,
                "messages_count": message_count,
                "agent": agent_name,
                "workspace": workspace,
                "title": session_title
            }
        });
        println!(
            "{}",
            serde_json::to_string_pretty(&result).unwrap_or_else(|_| "{}".to_string())
        );
    } else {
        println!("✓ Exported to {}", output_path.display());
        if encrypt {
            println!("  🔒 Encrypted with Web Crypto (AES-256-GCM)");
        }
        if human_turns > 0 {
            println!(
                "  {} prompts, {} responses, {} tool uses, {} bytes",
                human_turns, assistant_msgs, tool_use_count, file_size
            );
        } else {
            println!("  {} messages, {} bytes", message_count, file_size);
        }
    }

    Ok(())
}

/// Extract tool call information from a message for HTML export.
///
/// Supports multiple formats:
/// 1. Claude/Anthropic format: `content` array with `type: "tool_use"` or `type: "tool_result"` blocks
/// 2. Cursor/generic format: `type: "tool"` at top level with `message.tool_name`, `message.tool_input`, `message.tool_output`
fn extract_tool_call(msg: &serde_json::Value) -> Option<html_export::ToolCall> {
    // Format 2: Cursor/generic format - check for top-level type: "tool"
    if let Some(msg_type) = msg.get("type").and_then(|t| t.as_str())
        && msg_type == "tool"
    {
        // Look for tool info in the message object
        let inner = msg.get("message").unwrap_or(msg);

        let tool_name = inner
            .get("tool_name")
            .and_then(|n| n.as_str())
            .unwrap_or("tool");

        let tool_input = inner.get("tool_input").map(|i| {
            if i.is_object() || i.is_array() {
                serde_json::to_string_pretty(i).unwrap_or_default()
            } else if let Some(s) = i.as_str() {
                s.to_string()
            } else {
                i.to_string()
            }
        });

        let tool_output = inner.get("tool_output").map(|o| {
            if o.is_object() || o.is_array() {
                serde_json::to_string_pretty(o).unwrap_or_default()
            } else if let Some(s) = o.as_str() {
                s.to_string()
            } else {
                o.to_string()
            }
        });

        // Determine status from explicit status field or presence of output
        let status_str = inner
            .get("status")
            .and_then(|s| s.as_str())
            .or_else(|| msg.get("status").and_then(|s| s.as_str()));

        let status = match status_str {
            Some("success") => Some(html_export::ToolStatus::Success),
            Some("error") => Some(html_export::ToolStatus::Error),
            Some("pending") => Some(html_export::ToolStatus::Pending),
            _ if tool_output.is_some() => Some(html_export::ToolStatus::Success),
            // For exported conversations, don't show "pending" - just hide the status badge
            _ => None,
        };

        return Some(html_export::ToolCall {
            name: tool_name.to_string(),
            input: tool_input.unwrap_or_default(),
            output: tool_output,
            status,
        });
    }

    // Format 1: Claude/Anthropic format - content array with tool_use/tool_result blocks
    let content = msg
        .get("message")
        .and_then(|m| m.get("content"))
        .or_else(|| msg.get("content"));

    if let Some(arr) = content.and_then(|c| c.as_array()) {
        for block in arr {
            if let Some(block_type) = block.get("type").and_then(|t| t.as_str()) {
                match block_type {
                    "tool_use" => {
                        let name = block.get("name").and_then(|n| n.as_str()).unwrap_or("tool");
                        let input = block.get("input").map(|i| {
                            if i.is_object() || i.is_array() {
                                serde_json::to_string_pretty(i).unwrap_or_default()
                            } else if let Some(s) = i.as_str() {
                                s.to_string()
                            } else {
                                i.to_string()
                            }
                        });
                        return Some(html_export::ToolCall {
                            name: name.to_string(),
                            input: input.unwrap_or_default(),
                            output: None,
                            // For exported conversations, don't show "pending" for tool invocations
                            // without explicit status - the output may be in a separate message
                            status: None,
                        });
                    }
                    "tool_result" => {
                        let content = block.get("content").map(|c| {
                            if c.is_object() || c.is_array() {
                                serde_json::to_string_pretty(c).unwrap_or_default()
                            } else if let Some(s) = c.as_str() {
                                s.to_string()
                            } else {
                                c.to_string()
                            }
                        });
                        return Some(html_export::ToolCall {
                            name: "tool_result".to_string(),
                            input: String::new(),
                            output: content,
                            status: Some(html_export::ToolStatus::Success),
                        });
                    }
                    _ => {}
                }
            }
        }
    }

    None
}

// ============================================================================
// Message Grouping Algorithm for Consolidated HTML Export
// ============================================================================

/// Agent format for message structure detection.
///
/// Different coding agents use different message formats. This enum helps
/// the grouping algorithm understand how to parse and correlate messages.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AgentFormat {
    /// Claude Code: content array with tool_use/tool_result blocks, correlation via tool_use_id
    ClaudeCode,
    /// Codex CLI: function_call and function role messages, correlation via function name
    Codex,
    /// Cursor: type: "tool" at top level with tool_name/tool_input/tool_output
    Cursor,
    /// OpenCode: special handling already exists
    OpenCode,
    /// Generic/unknown format
    Generic,
}

/// Message classification for grouping decisions.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MessageClassification {
    /// User message with actual text content
    UserContent,
    /// Assistant message with text (may also have embedded tools)
    AssistantContent,
    /// Assistant message with only tool calls, no text
    AssistantToolOnly,
    /// Response to a tool call (tool_result, function response)
    ToolResult,
    /// System message
    System,
    /// Empty or skip-worthy message
    Empty,
}

/// Detect the agent format from a set of messages.
///
/// Examines message structure to determine which agent produced them.
/// This enables format-specific correlation logic.
pub fn detect_agent_format(messages: &[html_export::Message]) -> AgentFormat {
    use tracing::trace;

    // Check first few messages for format indicators
    for msg in messages.iter().take(10) {
        let role = msg.role.as_str();

        // Codex uses "function" role for tool results
        if role == "function" {
            trace!(
                agent_format = "codex",
                "Detected Codex format from function role"
            );
            return AgentFormat::Codex;
        }

        // Check for tool_call presence and structure
        if let Some(ref tc) = msg.tool_call {
            // Cursor format has specific tool names like "tool"
            if tc.name == "tool" || tc.name.starts_with("tool_") {
                trace!(
                    agent_format = "cursor",
                    "Detected Cursor format from tool name pattern"
                );
                return AgentFormat::Cursor;
            }
            // Claude Code uses standard tool names (Bash, Read, Write, etc.)
            if matches!(
                tc.name.as_str(),
                "Bash" | "Read" | "Write" | "Edit" | "Glob" | "Grep" | "Task" | "WebFetch"
            ) {
                trace!(
                    agent_format = "claude_code",
                    "Detected Claude Code format from tool name"
                );
                return AgentFormat::ClaudeCode;
            }
        }
    }

    trace!(
        agent_format = "generic",
        "Using generic format (no specific pattern detected)"
    );
    AgentFormat::Generic
}

/// Classify a message for grouping purposes.
///
/// Determines how a message should be handled in the grouping algorithm:
/// - Starting a new group
/// - Attaching to current group
/// - Being a tool result
/// - Being skipped
pub fn classify_message(msg: &html_export::Message, _format: AgentFormat) -> MessageClassification {
    use tracing::trace;

    let role = msg.role.as_str();
    let has_content = !msg.content.trim().is_empty();
    let has_tool = msg.tool_call.is_some();

    trace!(
        role = role,
        has_content = has_content,
        has_tool = has_tool,
        "Classifying message"
    );

    match role {
        "user" => {
            if has_content {
                MessageClassification::UserContent
            } else {
                MessageClassification::Empty
            }
        }
        "assistant" | "agent" => {
            if has_content {
                MessageClassification::AssistantContent
            } else if has_tool {
                MessageClassification::AssistantToolOnly
            } else {
                MessageClassification::Empty
            }
        }
        "tool" | "function" => {
            // Tool result messages
            MessageClassification::ToolResult
        }
        "system" => MessageClassification::System,
        _ => {
            // Unknown role - check if it has meaningful content
            if has_content || has_tool {
                MessageClassification::AssistantContent
            } else {
                MessageClassification::Empty
            }
        }
    }
}

/// Extract correlation ID from a message for tool call/result matching.
///
/// Different formats use different correlation mechanisms:
/// - Claude Code: tool_use_id in content blocks
/// - Codex: function call name
/// - Generic: message index fallback
pub fn extract_correlation_id(msg: &html_export::Message, format: AgentFormat) -> Option<String> {
    use tracing::trace;

    // First, try to use the tool call name as a simple correlation
    // This works for most formats as a baseline
    if let Some(ref tc) = msg.tool_call {
        let corr_id = match format {
            AgentFormat::ClaudeCode => {
                // Claude uses tool_use_id but we don't have access to raw JSON here
                // Fall back to tool name + index
                Some(format!("claude-{}", tc.name))
            }
            AgentFormat::Codex => {
                // Codex correlates by function name
                Some(format!("codex-{}", tc.name))
            }
            AgentFormat::Cursor => Some(format!("cursor-{}", tc.name)),
            AgentFormat::OpenCode => Some(format!("opencode-{}", tc.name)),
            AgentFormat::Generic => Some(format!("generic-{}", tc.name)),
        };
        trace!(correlation_id = ?corr_id, tool_name = %tc.name, "Extracted correlation ID");
        return corr_id;
    }

    // For tool results without explicit tool_call, use index as fallback
    msg.index.map(|idx| format!("index-{}", idx))
}

/// Flush the current group into the groups vector if it exists.
fn flush_group(
    groups: &mut Vec<html_export::MessageGroup>,
    current_group: &mut Option<html_export::MessageGroup>,
) {
    if let Some(group) = current_group.take() {
        tracing::trace!(
            group_type = ?group.group_type,
            tool_count = group.tool_count(),
            "Flushing message group"
        );
        groups.push(group);
    }
}

/// Groups flat messages into MessageGroups with tool correlation.
///
/// # Algorithm
/// 1. Detect agent format from message structure
/// 2. Classify each message
/// 3. User/Assistant content messages start new groups
/// 4. Tool-only messages attach to current assistant group
/// 5. Tool results correlate by ID to matching tool call
/// 6. System messages are standalone groups
/// 7. Track timestamps for group range
///
/// # Logging
/// - INFO: Group formation summary
/// - DEBUG: Each message classification
/// - TRACE: Correlation matching details
///
/// # Example
/// ```ignore
/// let messages: Vec<Message> = load_messages();
/// let groups = group_messages_for_export(messages);
/// for group in groups {
///     render_message_group(&group);
/// }
/// ```
pub fn group_messages_for_export(
    messages: Vec<html_export::Message>,
) -> Vec<html_export::MessageGroup> {
    use tracing::{debug, info, trace};

    info!(message_count = messages.len(), "Starting message grouping");

    let format = detect_agent_format(&messages);
    debug!(?format, "Detected agent format");

    let mut groups: Vec<html_export::MessageGroup> = Vec::new();
    let mut current_group: Option<html_export::MessageGroup> = None;

    for (idx, msg) in messages.iter().enumerate() {
        let classification = classify_message(msg, format);
        debug!(
            idx = idx,
            classification = ?classification,
            role = %msg.role,
            content_preview = %msg.content.chars().take(50).collect::<String>(),
            "Classified message"
        );

        match classification {
            MessageClassification::UserContent => {
                // User messages start a new group
                flush_group(&mut groups, &mut current_group);
                let group = html_export::MessageGroup::user(msg.clone());
                current_group = Some(group);
            }

            MessageClassification::AssistantContent => {
                // Assistant content starts a new group
                flush_group(&mut groups, &mut current_group);
                let mut group = html_export::MessageGroup::assistant(msg.clone());

                // If assistant has embedded tool calls, add them
                if let Some(ref tc) = msg.tool_call {
                    let corr_id = extract_correlation_id(msg, format);
                    group.add_tool_call(tc.clone(), corr_id);
                    trace!(tool_name = %tc.name, "Added embedded tool call to assistant group");
                }
                current_group = Some(group);
            }

            MessageClassification::AssistantToolOnly => {
                // Tool-only messages attach to current group or create tool-only group
                if let Some(ref mut g) = current_group {
                    // Attach to existing group
                    if let Some(ref tc) = msg.tool_call {
                        let corr_id = extract_correlation_id(msg, format);
                        g.add_tool_call(tc.clone(), corr_id);
                        g.update_end_timestamp(msg.timestamp.clone());
                        trace!(tool_name = %tc.name, "Attached tool call to current group");
                    }
                } else {
                    // Create a new tool-only group
                    let mut group = html_export::MessageGroup::tool_only(msg.clone());
                    if let Some(ref tc) = msg.tool_call {
                        let corr_id = extract_correlation_id(msg, format);
                        group.add_tool_call(tc.clone(), corr_id);
                    }
                    current_group = Some(group);
                    trace!("Created new tool-only group");
                }
            }

            MessageClassification::ToolResult => {
                // Tool results attach to current group
                if let Some(ref mut g) = current_group {
                    // Create a ToolResult from the message
                    let tool_name = msg
                        .tool_call
                        .as_ref()
                        .map(|tc| tc.name.clone())
                        .unwrap_or_else(|| "tool_result".to_string());

                    let content = if let Some(ref tc) = msg.tool_call {
                        tc.output.clone().unwrap_or_else(|| msg.content.clone())
                    } else {
                        msg.content.clone()
                    };

                    let status = msg
                        .tool_call
                        .as_ref()
                        .and_then(|tc| tc.status)
                        .unwrap_or(html_export::ToolStatus::Success);

                    let mut result =
                        html_export::ToolResult::new(tool_name.clone(), content, status);

                    // Try to get correlation ID
                    if let Some(corr_id) = extract_correlation_id(msg, format) {
                        result = result.with_correlation_id(corr_id);
                    }

                    g.add_tool_result(result);
                    g.update_end_timestamp(msg.timestamp.clone());
                    trace!(tool_name = %tool_name, "Added tool result to group");
                } else {
                    debug!(
                        idx = idx,
                        "Orphan tool result, no current group to attach to"
                    );
                }
            }

            MessageClassification::System => {
                // System messages are standalone groups
                flush_group(&mut groups, &mut current_group);
                let group = html_export::MessageGroup::system(msg.clone());
                groups.push(group);
                trace!("Added standalone system group");
            }

            MessageClassification::Empty => {
                trace!(idx = idx, "Skipping empty message");
            }
        }
    }

    // Flush any remaining group
    flush_group(&mut groups, &mut current_group);

    info!(
        group_count = groups.len(),
        original_messages = messages.len(),
        "Message grouping complete"
    );

    groups
}

